```class Solution {
    public boolean[] friendRequests(int n, int[][] restrictions, int[][] requests) {
        List<Set<Integer>> friends = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            friends.add(new HashSet<>());
        }
        for (int[] restriction : restrictions) {
            friends.get(restriction[0]).add(restriction[1]);
            friends.get(restriction[1]).add(restriction[0]);
        }
        boolean[] result = new boolean[requests.length];
        for (int i = 0; i < requests.length; i++) {
            int u = requests[i][0];
            int v = requests[i][1];
            if (friends.get(u).contains(v) || friends.get(v).contains(u)) {
                result[i] = true;
            } else {
                for (int friend : friends.get(u)) {
                    if (friend == v || friends.get(friend).contains(v)) {
                        result[i] = false;
                        break;
                    }
                }
            }
        }
        return result;
    }
}
